package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Method;

import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionAccessFilterHelperTest {

  AccessibleObject accessibleObjectMock;
  Object targetObject;

  @BeforeEach
  void setup() {
    accessibleObjectMock = mock(AccessibleObject.class);
    targetObject = new Object();
  }

  @Test
  void testCanAccess_delegatesToAccessChecker() throws Exception {
    // Mock AccessChecker.INSTANCE.canAccess to return true
    try (MockedStatic<ReflectionAccessFilterHelper.AccessChecker> accessCheckerStatic = Mockito.mockStatic(ReflectionAccessFilterHelper.AccessChecker.class)) {
      accessCheckerStatic.when(() -> ReflectionAccessFilterHelper.AccessChecker.INSTANCE.canAccess(accessibleObjectMock, targetObject))
          .thenReturn(true);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
      assertTrue(result);

      accessCheckerStatic.verify(() -> ReflectionAccessFilterHelper.AccessChecker.INSTANCE.canAccess(accessibleObjectMock, targetObject));
    }
  }

  @Test
  void testCanAccess_delegatesToAccessChecker_returnsFalse() throws Exception {
    try (MockedStatic<ReflectionAccessFilterHelper.AccessChecker> accessCheckerStatic = Mockito.mockStatic(ReflectionAccessFilterHelper.AccessChecker.class)) {
      accessCheckerStatic.when(() -> ReflectionAccessFilterHelper.AccessChecker.INSTANCE.canAccess(accessibleObjectMock, targetObject))
          .thenReturn(false);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
      assertFalse(result);

      accessCheckerStatic.verify(() -> ReflectionAccessFilterHelper.AccessChecker.INSTANCE.canAccess(accessibleObjectMock, targetObject));
    }
  }
}
